setup:
mkdir -p /tmp/eval_refactor && printf 'import json

def save_user(name, email):
    data = {"name": name, "email": email}
    with open("/tmp/eval_refactor/users.json", "w") as f:
        json.dump(data, f)

def load_user():
    with open("/tmp/eval_refactor/users.json") as f:
        return json.load(f)
' > /tmp/eval_refactor/storage.py && printf 'from storage import save_user, load_user

save_user("Alice", "alice@example.com")
user = load_user()
print(user["name"])
' > /tmp/eval_refactor/app.py
